// Worked focus: cmem-flexible-array-allocation — Allocate flexible-array objects with checked header-plus-elements arithmetic and record their element count.
/* Evidence: cmem-worked-cmem-structs-unions-flexible-arrays-5 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9035; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct packet_model { int tag; size_t count; int payload[4]; };

static int worked_cmem_structs_unions_flexible_arrays_5(const struct packet_model *packet, int *sum) {
  size_t index;
  int total = 0;
  if (packet == NULL || sum == NULL || packet->tag != 1 || packet->count > 4) return 0;
  for (index = 0; index < packet->count; ++index) total += packet->payload[index];
  *sum = total;
  return 1;
}

int main(void) {
  struct packet_model packet = { 1, 3, { 3, 4, 5, 0 } };
  int sum = 0;
  int accepted = worked_cmem_structs_unions_flexible_arrays_5(&packet, &sum);
  packet.tag = 9;
  int rejected = worked_cmem_structs_unions_flexible_arrays_5(&packet, &sum);
  int invariant = accepted && !rejected && sum == 12;
  printf("packet sum=%d invariant=%d\n", sum, invariant);
  return invariant ? 0 : 1;
}

